import * as React from "react"
import { useStaticQuery, graphql } from "gatsby"
import { StaticImage } from "gatsby-plugin-image"
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome'
import { faLinkedinIn, faTwitter, faGithub } from '@fortawesome/free-brands-svg-icons'
import { faG } from "@fortawesome/free-solid-svg-icons"

const SidePanel = () => {
  const data = useStaticQuery(graphql`
     query BioQuery {
       site {
         siteMetadata {
           author {
             name
             summary
           }
           social {
             twitter
           }
         }
       }
     }
   `)

  const author = data.site.siteMetadata?.author

  return (
    <div class="flex flex-col dark:bg-gray-800 dark:border-gray-600">
      <h2 class="text-3xl font-semibold text-center text-gray-800 dark:text-white">{author.name}</h2>

      <div class="flex flex-col items-center mt-6">
        <StaticImage
          className="object-cover w-24 h-24 mx-2 rounded-full"
          layout="fixed"
          formats={["auto", "webp", "avif"]}
          src="../images/profile-pic.png"
          width={100}
          height={100}
          quality={95}
          alt="Profile picture"
        />
        <h4 class="font-medium text-gray-800 text-center">{author?.summary || null}</h4>
        <p class="text-sm font-medium text-gray-600 s">john@example.com</p>
        <div>
          <a >
            <FontAwesomeIcon icon={faLinkedinIn} />
          </a>
          <a>
            <FontAwesomeIcon icon={faGithub} />
          </a>
          <a>
            <FontAwesomeIcon icon={faTwitter} />
          </a>
        </div>
      </div>
    </div>
  )
}

export default SidePanel
